package com.shanfuchun.courtassistant.download

import android.content.Context
import android.util.Log
import com.shanfuchun.courtassistant.data.AppDatabase
import com.shanfuchun.courtassistant.data.DocumentRecord
import com.shanfuchun.courtassistant.download.detector.PdfLinkDetector
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.runBlocking
import kotlinx.coroutines.withContext
import okhttp3.OkHttpClient
import okhttp3.Request
import java.io.File
import java.net.URI
import java.util.concurrent.TimeUnit

/**
 * PDF下载核心模块
 * 负责PDF文件的下载、验证和记录
 */
class PdfDownloader private constructor(
    private val client: OkHttpClient,
    private val detector: PdfLinkDetector
) {

    companion object {
        private const val TAG = "PdfDownloader"

        fun create(): PdfDownloader {
            val client = OkHttpClient.Builder()
                .followRedirects(true)
                .connectTimeout(30, TimeUnit.SECONDS)
                .readTimeout(60, TimeUnit.SECONDS)
                .build()

            val detector = PdfLinkDetector.create()
            return PdfDownloader(client, detector)
        }
    }

    /**
     * 从URL列表下载PDF文件
     */
    suspend fun downloadFromUrls(context: Context, db: AppDatabase, smsId: Long, urls: List<String>) {
        withContext(Dispatchers.IO) {
            for (url in urls) {
                try {
                    Log.d(TAG, "PdfDownloader: processing url=$url")
                    if (url.lowercase().endsWith(".pdf")) {
                        downloadPdf(context, db, smsId, url, "")
                    } else {
                        val pdfLinks = detector.discoverPdfLinks(url)
                        Log.d(TAG, "PdfDownloader: discovered ${pdfLinks.size} pdf links from page")
                        if (pdfLinks.isNotEmpty()) {
                            var downloaded = 0
                            for ((pdfUrl, displayName) in pdfLinks) {
                                if (db.documentDao().findDownloadedByUrlAndSms(pdfUrl, smsId) != null) { downloaded++; continue }
                                val docId = tryDownloadPdf(context, db, smsId, pdfUrl, displayName)
                                if (docId) downloaded++
                            }
                            // 监督：如果未全部下载，保留待下载记录供用户重试
                            if (downloaded < pdfLinks.size) {
                                val pending = db.documentDao().findByUrlAndSms(url, smsId)
                                if (pending == null) {
                                    savePendingUrl(db, smsId, url, "未下载完全($downloaded/${pdfLinks.size}) 点击重试")
                                }
                            } else {
                                // 全部成功，删除该页面的待下载记录
                                val pending = db.documentDao().findByUrlAndSms(url, smsId)
                                if (pending != null && pending.parseStatus == 4) {
                                    db.documentDao().delete(pending)
                                }
                            }
                        } else {
                            Log.d(TAG, "PdfDownloader: no PDFs found via Jsoup, queuing for WebView: $url")
                            savePendingUrl(db, smsId, url)
                        }
                    }
                } catch (e: Exception) {
                    Log.e(TAG, "PdfDownloader: error processing url=$url", e)
                    savePendingUrl(db, smsId, url)
                }
            }
        }
    }

    /**
     * 尝试下载PDF文件 - 对非PDF链接的内容进行验证
     */
    private suspend fun tryDownloadPdf(context: Context, db: AppDatabase, smsId: Long, url: String, displayName: String): Boolean {
        if (url.lowercase().let { it.endsWith(".pdf") || it.contains(".pdf?") }) {
            return downloadPdf(context, db, smsId, url, displayName) > 0
        }
        try {
            val request = Request.Builder().url(url).head().build()
            val response = client.newCall(request).execute()
            val contentType = response.header("Content-Type", "") ?: ""
            if (contentType.contains("pdf", ignoreCase = true)) {
                return downloadPdf(context, db, smsId, url, displayName) > 0
            } else {
                Log.d(TAG, "PdfDownloader: skipping non-PDF url=$url contentType=$contentType")
                return false
            }
        } catch (e: Exception) {
            // HEAD失败，尝试直接下载
            return downloadPdf(context, db, smsId, url, displayName) > 0
        }
    }

    /**
     * 下载PDF文件
     */
    suspend fun downloadPdf(context: Context, db: AppDatabase, smsId: Long, url: String, displayName: String = ""): Long {
        val dir = File(context.filesDir, "pdfs").also { it.mkdirs() }
        val fileName = extractFileName(url)
        val file = File(dir, "${System.currentTimeMillis()}_$fileName")

        Log.d(TAG, "PdfDownloader: downloading $url -> ${file.name}")
        val request = Request.Builder().url(url).build()
        val response = client.newCall(request).execute()
        if (!response.isSuccessful) {
            Log.e(TAG, "PdfDownloader: HTTP ${response.code}");
            return -1
        }
        response.body?.byteStream()?.use { input ->
            file.outputStream().use { output -> input.copyTo(output) }
        }
        if (file.length() == 0L) {
            file.delete();
            return -1
        }
        Log.d(TAG, "PdfDownloader: downloaded ${file.length()} bytes")

        val docId = db.documentDao().insert(
            DocumentRecord(
                smsId = smsId,
                fileName = fileName,
                filePath = file.absolutePath,
                fileSize = file.length(),
                sourceUrl = url,
                downloadTime = System.currentTimeMillis(),
                displayName = displayName.ifEmpty { fileName }
            )
        )

        // 解析PDF并同步到数据库
        com.shanfuchun.courtassistant.service.parser.PdfParser.parseAndSync(context, db, docId)
        return docId
    }

    /**
     * PDF下载完成后的回调处理
     */
    suspend fun onPdfDownloaded(context: Context, db: AppDatabase, docId: Long, file: File) {
        val doc = db.documentDao().getById(docId) ?: return
        db.documentDao().update(doc.copy(
            fileName = file.name,
            filePath = file.absolutePath,
            fileSize = file.length(),
            parseStatus = 0
        ))

        // 解析PDF并同步到数据库
        com.shanfuchun.courtassistant.service.parser.PdfParser.parseAndSync(context, db, docId)
    }

    /**
     * 保存待下载URL记录
     */
    suspend fun savePendingUrl(db: AppDatabase, smsId: Long, url: String, label: String = "待下载文书") {
        if (db.documentDao().findByUrlAndSms(url, smsId) != null) return
        db.documentDao().insert(
            DocumentRecord(
                smsId = smsId,
                fileName = label,
                filePath = "",
                fileSize = 0,
                sourceUrl = url,
                downloadTime = System.currentTimeMillis(),
                parseStatus = 4,
                displayName = label
            )
        )
    }

    /**
     * 同步保存待下载URL记录（用于非suspend上下文）
     */
    fun savePendingUrlSync(db: AppDatabase, smsId: Long, url: String, label: String = "待下载文书") {
        // 使用Thread在后台执行数据库操作
        Thread {
            try {
                // 先查询是否已存在
                val existing = runBlocking {
                    db.documentDao().findByUrlAndSms(url, smsId)
                }
                if (existing != null) return@Thread

                // 插入新记录
                runBlocking {
                    db.documentDao().insert(
                        DocumentRecord(
                            smsId = smsId,
                            fileName = label,
                            filePath = "",
                            fileSize = 0,
                            sourceUrl = url,
                            downloadTime = System.currentTimeMillis(),
                            parseStatus = 4,
                            displayName = label
                        )
                    )
                }
            } catch (e: Exception) {
                Log.e(TAG, "Error saving pending URL", e)
            }
        }.start()
    }

    /**
     * 从URL提取文件名
     */
    private fun extractFileName(url: String): String {
        val path = try { URI(url).path } catch (_: Exception) { null } ?: return "document.pdf"
        val name = path.substringAfterLast("/")
        return if (name.isNotBlank() && name.length < 100) name else "document.pdf"
    }
}

package com.shanfuchun.courtassistant.download

import android.content.Context
import android.util.Log
import com.shanfuchun.courtassistant.data.AppDatabase
import kotlinx.coroutines.*
import java.util.concurrent.ConcurrentHashMap
import java.util.concurrent.atomic.AtomicBoolean

/**
 * 下载任务管理器
 * 负责管理下载任务的执行、状态跟踪和资源清理
 */
class DownloadManager private constructor(
    private val context: Context,
    private val db: AppDatabase,
    private val pdfDownloader: PdfDownloader
) {

    companion object {
        private const val TAG = "DownloadManager"

        @Volatile
        private var INSTANCE: DownloadManager? = null

        fun getInstance(context: Context, db: AppDatabase): DownloadManager {
            return INSTANCE ?: synchronized(this) {
                INSTANCE ?: DownloadManager(
                    context.applicationContext,
                    db,
                    PdfDownloader.create()
                ).also { INSTANCE = it }
            }
        }
    }

    // 活跃的下载任务
    private val activeDownloads = ConcurrentHashMap<String, Job>()
    private val isProcessing = AtomicBoolean(false)

    /**
     * 开始下载任务
     */
    fun startDownload(smsId: Long, urls: List<String>): String {
        val downloadId = "download_${System.currentTimeMillis()}_${smsId}"

        // 取消同类型的旧任务
        cancelOldDownloads(smsId)

        // 创建新任务
        val job = CoroutineScope(Dispatchers.IO).launch {
            try {
                isProcessing.set(true)
                pdfDownloader.downloadFromUrls(context, db, smsId, urls)
                Log.d(TAG, "Download completed for smsId=$smsId")
            } catch (e: Exception) {
                Log.e(TAG, "Download failed for smsId=$smsId", e)
            } finally {
                isProcessing.set(false)
                activeDownloads.remove(downloadId)
            }
        }

        activeDownloads[downloadId] = job
        return downloadId
    }

    /**
     * 取消指定的下载任务
     */
    fun cancelDownload(downloadId: String): Boolean {
        return activeDownloads[downloadId]?.let { job ->
            if (job.isActive) {
                job.cancel()
                activeDownloads.remove(downloadId)
                true
            } else {
                false
            }
        } ?: false
    }

    /**
     * 取消指定短信ID的所有下载任务
     */
    fun cancelOldDownloads(smsId: Long) {
        activeDownloads.entries.removeAll { (downloadId, job) ->
            if (downloadId.contains("_$smsId")) {
                if (job.isActive) {
                    job.cancel()
                }
                true
            } else {
                false
            }
        }
    }

    /**
     * 获取下载进度
     */
    fun getDownloadProgress(): Map<String, DownloadStatus> {
        return activeDownloads.mapValues { (downloadId, job) ->
            when {
                !job.isActive -> DownloadStatus.COMPLETED
                job.isCompleted -> DownloadStatus.COMPLETED
                job.isCancelled -> DownloadStatus.CANCELLED
                isProcessing.get() -> DownloadStatus.IN_PROGRESS
                else -> DownloadStatus.PENDING
            }
        }
    }

    /**
     * 检查是否有活跃的下载任务
     */
    fun hasActiveDownloads(): Boolean {
        return activeDownloads.values.any { it.isActive }
    }

    /**
     * 清理所有下载任务
     */
    fun cleanup() {
        activeDownloads.forEach { (downloadId, job) ->
            if (job.isActive) {
                job.cancel()
            }
        }
        activeDownloads.clear()
        isProcessing.set(false)
    }

    /**
     * 获取PDF下载器实例（用于直接操作）
     */
    fun getPdfDownloader(): PdfDownloader = pdfDownloader

    /**
     * 下载状态枚举
     */
    enum class DownloadStatus {
        PENDING,
        IN_PROGRESS,
        COMPLETED,
        CANCELLED
    }

    /**
     * 清理资源（在应用退出时调用）
     */
    fun destroy() {
        cleanup()
        INSTANCE = null
    }
}

