package com.shanfuchun.courtassistant.download

import android.content.Context
import android.util.Log
import com.shanfuchun.courtassistant.data.AppDatabase
import com.shanfuchun.courtassistant.data.DocumentRecord
import com.shanfuchun.courtassistant.download.detector.PdfLinkDetector
import com.shanfuchun.courtassistant.download.handler.FileDownloadHandler
import com.shanfuchun.courtassistant.download.handler.WebViewDownloadHandler
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.withContext
import okhttp3.OkHttpClient
import java.util.concurrent.TimeUnit
import javax.inject.Inject
import javax.inject.Singleton

/**
 * 下载管理器
 * 负责管理下载任务、状态追踪和处理器分发
 */
@Singleton
class DownloadManager @Inject constructor(
    private val httpClient: OkHttpClient,
    private val pdfLinkDetector: PdfLinkDetector,
    private val fileDownloadHandler: FileDownloadHandler,
    private val webViewDownloadHandler: WebViewDownloadHandler
) {

    companion object {
        private const val TAG = "DownloadManager"
    }

    // 下载状态流
    private val _downloadState = MutableStateFlow<DownloadState>(DownloadState.Idle)
    val downloadState: Flow<DownloadState> = _downloadState.asStateFlow()

    // 活跃的下载任务
    private val activeDownloads = mutableMapOf<String, DownloadTask>()

    /**
     * 批量下载PDF文件
     */
    suspend fun downloadBatch(
        context: Context,
        db: AppDatabase,
        smsId: Long,
        urls: List<String>
    ): BatchDownloadResult {
        _downloadState.value = DownloadState.Downloading(urls.size)

        return withContext(Dispatchers.IO) {
            var successful = 0
            var failed = 0
            val results = mutableListOf<DownloadResult>()

            for (url in urls) {
                try {
                    _downloadState.value = DownloadState.Progress(
                        current = successful + failed + 1,
                        total = urls.size,
                        currentUrl = url
                    )

                    Log.d(TAG, "Processing URL: $url")
                    val result = downloadSingle(context, db, smsId, url)
                    results.add(result)

                    if (result.isSuccess) {
                        successful++
                    } else {
                        failed++
                    }
                } catch (e: Exception) {
                    Log.e(TAG, "Error processing URL: $url", e)
                    failed++
                    results.add(DownloadResult(url = url, isSuccess = false, error = e.message))
                }
            }

            _downloadState.value = DownloadState.Completed(successful, failed)
            BatchDownloadResult(successful, failed, results)
        }
    }

    /**
     * 下载单个URL
     */
    private suspend fun downloadSingle(
        context: Context,
        db: AppDatabase,
        smsId: Long,
        url: String
    ): DownloadResult {
        // 检查是否已下载过
        if (db.documentDao().findDownloadedByUrlAndSms(url, smsId) != null) {
            Log.d(TAG, "Already downloaded: $url")
            return DownloadResult(url = url, isSuccess = true, message = "Already downloaded")
        }

        // 选择合适的下载处理器
        val handler = selectHandler(url)

        // 创建下载任务
        val taskId = "task_${System.currentTimeMillis()}"
        val task = DownloadTask(taskId, url, smsId)
        activeDownloads[taskId] = task

        try {
            val result = handler.handle(context, db, task)
            activeDownloads.remove(taskId)
            return result
        } catch (e: Exception) {
            activeDownloads.remove(taskId)
            throw e
        }
    }

    /**
     * 选择下载处理器
     */
    private fun selectHandler(url: String): DownloadHandler {
        return when {
            url.lowercase().endsWith(".pdf") -> fileDownloadHandler
            else -> {
                // 先尝试检测PDF链接
                if (pdfLinkDetector.isPdfUrl(url)) {
                    fileDownloadHandler
                } else {
                    webViewDownloadHandler
                }
            }
        }
    }

    /**
     * 取消活跃的下载任务
     */
    fun cancelTask(taskId: String): Boolean {
        return activeDownloads.remove(taskId) != null
    }

    /**
     * 获取活跃任务数量
     */
    fun getActiveTaskCount(): Int = activeDownloads.size

    /**
     * 清理所有活跃任务
     */
    fun clearActiveTasks() {
        activeDownloads.clear()
    }
}

/**
 * 下载状态
 */
sealed class DownloadState {
    object Idle : DownloadState()
    data class Downloading(val total: Int) : DownloadState()
    data class Progress(
        val current: Int,
        val total: Int,
        val currentUrl: String? = null
    ) : DownloadState()
    data class Completed(val successful: Int, val failed: Int) : DownloadState()
}

/**
 * 批量下载结果
 */
data class BatchDownloadResult(
    val successful: Int,
    val failed: Int,
    val results: List<DownloadResult>
)

/**
 * 单个下载结果
 */
data class DownloadResult(
    val url: String,
    val isSuccess: Boolean,
    val message: String? = null,
    val docId: Long? = null,
    val error: String? = null
)

/**
 * 下载任务
 */
data class DownloadTask(
    val id: String,
    val url: String,
    val smsId: Long,
    val startTime: Long = System.currentTimeMillis(),
    var status: TaskStatus = TaskStatus.Pending
)

/**
 * 任务状态
 */
enum class TaskStatus {
    Pending,
    Running,
    Completed,
    Failed,
    Cancelled
}

/**
 * 下载处理器接口
 */
interface DownloadHandler {
    suspend fun handle(
        context: Context,
        db: AppDatabase,
        task: DownloadTask
    ): DownloadResult
}

