package com.shanfuchun.courtassistant.download.detector

import android.util.Log
import com.shanfuchun.courtassistant.download.detector.JsoupDetector
import com.shanfuchun.courtassistant.download.detector.ScriptDetector
import okhttp3.OkHttpClient
import okhttp3.Request
import java.net.URI
import javax.inject.Inject
import javax.inject.Singleton

/**
 * PDF链接检测器
 * 负责从网页中检测和提取PDF链接
 */
@Singleton
class PdfLinkDetector @Inject constructor(
    private val jsoupDetector: JsoupDetector,
    private val scriptDetector: ScriptDetector,
    private val httpClient: OkHttpClient
) {

    companion object {
        private const val TAG = "PdfLinkDetector"
    }

    /**
     * 从URL发现PDF链接
     */
    suspend fun discoverPdfLinks(pageUrl: String): List<Pair<String, String>> {
        return try {
            // 先尝试使用Jsoup检测
            val jsoupResult = jsoupDetector.detect(pageUrl)
            if (jsoupResult.isNotEmpty()) {
                Log.d(TAG, "Detected ${jsoupResult.size} PDF links via Jsoup")
                return jsoupResult
            }

            // Jsoup失败，尝试直接下载检测
            val directResult = detectDirectDownload(pageUrl)
            if (directResult.isNotEmpty()) {
                Log.d(TAG, "Detected ${directResult.size} PDF links via direct download")
                return directResult
            }

            // 如果没有直接链接，扫描script标签
            val scriptResult = scriptDetector.detect(pageUrl)
            if (scriptResult.isNotEmpty()) {
                Log.d(TAG, "Detected ${scriptResult.size} PDF links via script scan")
                return scriptResult
            }

            emptyList()
        } catch (e: Exception) {
            Log.e(TAG, "Error detecting PDF links from $pageUrl", e)
            emptyList()
        }
    }

    /**
     * 检查是否是PDF URL
     */
    fun isPdfUrl(url: String): Boolean {
        return url.lowercase().let { it.endsWith(".pdf") || it.contains(".pdf?") }
    }

    /**
     * 直接下载检测
     */
    private suspend fun detectDirectDownload(pageUrl: String): List<Pair<String, String>> {
        try {
            val request = Request.Builder()
                .url(pageUrl)
                .head()
                .build()

            val response = httpClient.newCall(request).execute()
            val contentType = response.header("Content-Type", "") ?: ""

            // 如果直接返回PDF，则返回该URL
            if (contentType.contains("pdf", ignoreCase = true)) {
                val fileName = extractFileName(pageUrl)
                return listOf(pageUrl to fileName)
            }

            return emptyList()
        } catch (e: Exception) {
            Log.d(TAG, "Direct download detection failed for $pageUrl", e)
            return emptyList()
        }
    }

    /**
     * 从URL提取文件名
     */
    private fun extractFileName(url: String): String {
        return try {
            val path = url.substringBefore("?").substringAfterLast("/")
            if (path.isNotBlank() && path.length < 100) {
                path.removeSuffix(".pdf").removeSuffix(".PDF")
            } else {
                "文档"
            }
        } catch (e: Exception) {
            "文档"
        }
    }

    /**
     * 关键词列表
     */
    private val docKeywords = listOf(
        "传票", "判决", "裁定", "通知", "文书",
        "送达", "起诉", "应诉", "调解", "下载",
        "起诉状", "答辩状", "证据", "判决书", "裁定书"
    )

    /**
     * 判断文本是否包含法律文书关键词
     */
    fun containsDocKeywords(text: String): Boolean {
        return docKeywords.any { keyword ->
            text.contains(keyword)
        }
    }
}

