package com.shanfuchun.courtassistant.download.detector

/**
 * PDF 链接检测器
 *
 * 职责：检测 URL 是否指向 PDF 文件
 */
interface PdfLinkDetector {
    fun isPdfLink(url: String): Boolean
    fun getConfidence(url: String): Float
}

/**
 * 基于 URL 模式的 PDF 检测器
 */
object UrlBasedPdfDetector : PdfLinkDetector {

    private val pdfExtensions = listOf("pdf", "PDF")
    private val pdfKeywords = listOf("pdf", "document", "file", "download", "attachment", "content-disposition")

    override fun isPdfLink(url: String): Boolean {
        val lowerUrl = url.lowercase()
        return pdfExtensions.any { lowerUrl.endsWith(".$it") } ||
               pdfKeywords.any { lowerUrl.contains(it) }
    }

    override fun getConfidence(url: String): Float {
        val lowerUrl = url.lowercase()

        // 高置信度：.pdf 扩展名
        if (lowerUrl.endsWith(".pdf")) return 1.0f

        // 中等置信度：URL 中包含 pdf 关键词
        if (pdfKeywords.any { lowerUrl.contains(it) }) return 0.7f

        // 低置信度：不确定
        return 0.3f
    }
}

/**
 * 基于 HTTP Content-Type 的 PDF 检测器
 */
object ContentTypePdfDetector : PdfLinkDetector {

    private val pdfContentTypes = listOf(
        "application/pdf",
        "application/x-pdf",
        "application/octet-stream" // 某些服务器返回 octet-stream 但实际是 PDF
    )

    override fun isPdfLink(url: String): Boolean {
        // 这个检测器需要 HTTP 响应头信息
        // 默认返回 false
        return false
    }

    override fun getConfidence(url: String): Float {
        // 无法确定置信度
        return 0.5f
    }

    /**
     * 根据 Content-Type 判断
     *
     * @param contentType HTTP 响应的 Content-Type
     * @return 是否为 PDF
     */
    fun isPdfContentType(contentType: String?): Boolean {
        if (contentType == null) return false
        val lowerType = contentType.lowercase()
        return pdfContentTypes.contains(lowerType)
    }
}

