                .userAgent("Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36")
                .timeout(15000)
                .get()

            val baseUri = URI(pageUrl)

            // 匹配 <a> 链接：URL含.pdf 或 文字含法律文书关键词
            for (link in doc.select("a[href], a[onclick]")) {
                val href = link.attr("abs:href").ifEmpty { link.attr("href") }
                if (href.isBlank()) continue

                val resolved = try { baseUri.resolve(href).toString() } catch (_: Exception) { href }
                val text = link.text().trim()
                val title = link.attr("title").trim()
                val dataName = link.attr("data-name").trim()

                val isPdfUrl = resolved.lowercase().let { it.endsWith(".pdf") || it.contains(".pdf?") }
                val hasKeyword = containsDocKeywords(text) || containsDocKeywords(title)

                if (isPdfUrl || hasKeyword) {
                    // 优先级：dataName > title > text > URL提取的文件名
                    var displayName = dataName.ifEmpty { title }
                    if (displayName.isEmpty()) displayName = text
                    if (displayName.isEmpty()) {
                        displayName = extractNameFromUrl(resolved)
                    }
                    result.add(resolved to displayName)
                }
            }

            // 匹配 <iframe>/<embed> 嵌入的 PDF
            for (el in doc.select("iframe[src], embed[src], object[data]")) {
                val src = el.attr("abs:src").ifEmpty { el.attr("src").ifEmpty { el.attr("data") } }
                if (src.isBlank()) continue

                val resolved = try { baseUri.resolve(src).toString() } catch (_: Exception) { src }
                if (resolved.lowercase().let { it.contains(".pdf") || it.contains("pdf") }) {
                    val name = el.attr("title").ifEmpty { "嵌入文档" }
                    result.add(resolved to name)
                }
            }

            // 扫描script标签中的PDF URL
            for (script in doc.select("script")) {
                val scriptText = script.html()
                if (scriptText.contains(".pdf", ignoreCase = true)) {
                    val pattern = Regex("""['"]([^'"]*\.pdf[^'"]*)['"]""", RegexOption.IGNORE_CASE)
                    pattern.findAll(scriptText).forEach { match ->
                        val pdfUrl = match.groupValues[1]
                        val resolved = try {
                            if (pdfUrl.startsWith("http")) pdfUrl
                            else baseUri.resolve(pdfUrl).toString()
                        } catch (_: Exception) { pdfUrl }

                        if (resolved.lowercase().contains(".pdf")) {
                            val name = extractNameFromUrl(resolved)
                            result.add(resolved to name)
                        }
                    }
                }
            }

            Log.d(TAG, "Detected ${result.size} PDF links from $pageUrl")
            result.distinctBy { it.first }
        } catch (e: Exception) {
            Log.e(TAG, "Jsoup parsing failed for $pageUrl: ${e.message}")
            emptyList()
        }
    }

    /**
     * 法律文书关键词列表
     */
    private val docKeywords = listOf(
        "传票", "判决", "裁定", "通知", "文书",
        "送达", "起诉", "应诉", "调解", "下载",
        "起诉状", "答辩状", "证据", "判决书", "裁定书",
        "执行", "异议", "反诉", "上诉", "申请"
    )

    /**
     * 判断文本是否包含法律文书关键词
     */
    private fun containsDocKeywords(text: String): Boolean {
        return docKeywords.any { keyword ->
            text.contains(keyword)
        }
    }

    /**
     * 从URL提取文件名
     */
    private fun extractNameFromUrl(url: String): String {
        return try {
            val path = url.substringBefore("?").substringAfterLast("/")
            if (path.isNotBlank() && path.length < 100) {
                path.removeSuffix(".pdf").removeSuffix(".PDF")
            } else {
                "文档"
            }
        } catch (e: Exception) {
            "文档"
        }
    }
}

package com.shanfuchun.courtassistant.download.detector

import android.util.Log
import java.net.URI
import javax.inject.Inject
import javax.inject.Singleton

/**
 * 脚本PDF链接检测器
 * 扫描HTML页面中的JavaScript代码，提取PDF链接
 */
@Singleton
class ScriptDetector @Inject constructor() {

    companion object {
        private const val TAG = "ScriptDetector"
    }

    /**
     * 扫描页面中的JavaScript代码，提取PDF链接
     */
    suspend fun detect(pageUrl: String): List<Pair<String, String>> {
        return try {
            val result = mutableListOf<Pair<String, String>>()

            // 获取页面内容
            val doc = org.jsoup.Jsoup.connect(pageUrl)
                .userAgent("Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36")
                .timeout(15000)
                .get()

            val baseUri = URI(pageUrl)

            // 扫描所有script标签
            for (script in doc.select("script")) {
                val scriptText = script.html()
                if (scriptText.contains(".pdf", ignoreCase = true)) {
                    extractPdfLinksFromScript(scriptText, baseUri, result)
                }
            }

            Log.d(TAG, "Detected ${result.size} PDF links from scripts in $pageUrl")
            result.distinctBy { it.first }
        } catch (e: Exception) {
            Log.e(TAG, "Script scan failed for $pageUrl: ${e.message}")
            emptyList()
        }
    }

    /**
     * 从JavaScript代码中提取PDF链接
     */
    private fun extractPdfLinksFromScript(
        scriptText: String,
        baseUri: URI,
        result: MutableList<Pair<String, String>>
    ) {
        // 匹配PDF URL的各种模式
        val patterns = listOf(
            // 单引号包围的PDF URL
            Regex("""['"]([^'"]*\.pdf[^'"]*)['"]""", RegexOption.IGNORE_CASE),
            // 双引号包围的PDF URL
            Regex("""["']([^"']*\.pdf[^"']*)["']""", RegexOption.IGNORE_CASE),
            // url()中的PDF URL
            Regex("""url\(['"]([^'"]*\.pdf[^'"]*)['"]\)""", RegexOption.IGNORE_CASE),
            // window.location.href相关的PDF URL
            Regex("""window\.location\.href\s*=\s*['"]([^'"]*\.pdf[^'"]*)['"]""", RegexOption.IGNORE_CASE),
            // fetch请求中的PDF URL
            Regex("""fetch\(['"]([^'"]*\.pdf[^'"]*)['"]""", RegexOption.IGNORE_CASE),
            // AJAX请求中的PDF URL
            Regex("""\$\.(?:ajax|get)\(\s*{[^}]*url\s*:\s*['"]([^'"]*\.pdf[^'"]*)['"]""", RegexOption.IGNORE_CASE)
        )

        // 使用所有模式进行匹配
        for (pattern in patterns) {
            pattern.findAll(scriptText).forEach { match ->
                val pdfUrl = match.groupValues[1]
                val resolved = resolveUrl(pdfUrl, baseUri)

                if (resolved.lowercase().contains(".pdf")) {
                    val name = extractNameFromUrl(resolved)
                    result.add(resolved to name)
                }
            }
        }
    }

    /**
     * 解析相对URL为绝对URL
     */
    private fun resolveUrl(url: String, baseUri: URI): String {
        return try {
            if (url.startsWith("http://") || url.startsWith("https://")) {
                url
            } else {
                baseUri.resolve(url).toString()
            }
        } catch (e: Exception) {
            Log.d(TAG, "Failed to resolve URL: $url", e)
            url
        }
    }

    /**
     * 从URL提取文件名
     */
    private fun extractNameFromUrl(url: String): String {
        return try {
            val path = url.substringBefore("?").substringAfterLast("/")
            if (path.isNotBlank() && path.length < 100) {
                path.removeSuffix(".pdf").removeSuffix(".PDF")
            } else {
                "文档"
            }
        } catch (e: Exception) {
            "文档"
        }
    }

    /**
     * 专门用于JavaScript的PDF URL检测
     */
    fun detectFromJavaScript(jsCode: String): List<String> {
        val pdfUrls = mutableListOf<String>()

        // 匹配各种JavaScript中的PDF URL模式
        val patterns = listOf(
            Regex("""['"]([^'"]*\.pdf[^'"]*)['"]""", RegexOption.IGNORE_CASE),
            Regex("""url\(['"]([^'"]*\.pdf[^'"]*)['"]\)""", RegexOption.IGNORE_CASE),
            Regex("""fetch\(['"]([^'"]*\.pdf[^'"]*)['"]""", RegexOption.IGNORE_CASE)
        )

        patterns.forEach { pattern ->
            pattern.findAll(jsCode).forEach { match ->
                val url = match.groupValues[1]
                if (url.lowercase().contains(".pdf")) {
                    pdfUrls.add(url)
                }
            }
        }

        return pdfUrls.distinct()
    }
}

package com.shanfuchun.courtassistant.download.handler

import android.content.Context
import android.util.Log
import com.shanfuchun.courtassistant.data.AppDatabase
import com.shanfuchun.courtassistant.data.DocumentRecord
import com.shanfuchun.courtassistant.download.DownloadResult
import com.shanfuchun.courtassistant.download.DownloadTask
import com.shanfuchun.courtassistant.download.DownloadHandler
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import okhttp3.OkHttpClient
import okhttp3.Request
import java.io.File
import java.net.URI
import java.util.concurrent.TimeUnit
import javax.inject.Inject
import javax.inject.Singleton

/**
 * 文件下载处理器
 * 处理直接的PDF文件下载，包括文件验证和存储
 */
@Singleton
class FileDownloadHandler @Inject constructor(
    private val httpClient: OkHttpClient
) : DownloadHandler {

    companion object {
        private const val TAG = "FileDownloadHandler"
        private const val BUFFER_SIZE = 8192
    }

    /**
     * 处理文件下载任务
     */
    override suspend fun handle(
        context: Context,
        db: AppDatabase,
        task: DownloadTask
    ): DownloadResult {
        return withContext(Dispatchers.IO) {
            try {
                task.status = com.shanfuchun.courtassistant.download.DownloadManager.TaskStatus.Running

                // 验证URL是否指向PDF
                if (!validatePdfUrl(task.url)) {
                    Log.d(TAG, "URL is not a PDF: ${task.url}")
                    return@withContext DownloadResult(
                        url = task.url,
                        isSuccess = false,
                        message = "URL is not a valid PDF link"
                    )
                }

                // 执行下载
                val docId = downloadPdfFile(context, db, task)

                if (docId != null) {
                    DownloadResult(
                        url = task.url,
                        isSuccess = true,
                        docId = docId,
                        message = "PDF downloaded successfully"
                    )
                } else {
                    DownloadResult(
                        url = task.url,
                        isSuccess = false,
                        message = "Failed to download PDF"
                    )
                }
            } catch (e: Exception) {
                Log.e(TAG, "Error downloading PDF: ${task.url}", e)
                DownloadResult(
                    url = task.url,
                    isSuccess = false,
                    error = e.message ?: "Unknown error"
                )
            } finally {
                task.status = com.shanfuchun.courtassistant.download.DownloadManager.TaskStatus.Completed
            }
        }
    }

    /**
     * 验证URL是否指向PDF
     */
    private suspend fun validatePdfUrl(url: String): Boolean {
        if (url.lowercase().endsWith(".pdf") || url.contains(".pdf?")) {
            return true
        }

        // 通过HEAD请求验证Content-Type
        try {
            val request = Request.Builder()
                .url(url)
                .head()
                .build()

            val response = httpClient.newCall(request).execute()
            val contentType = response.header("Content-Type", "") ?: ""

            return contentType.contains("pdf", ignoreCase = true)
        } catch (e: Exception) {
            Log.d(TAG, "Failed to validate PDF URL: $url", e)
            return false
        }
    }

    /**
     * 下载PDF文件
     */
    private suspend fun downloadPdfFile(
        context: Context,
        db: AppDatabase,
        task: DownloadTask
    ): Long? {
        val dir = File(context.filesDir, "pdfs").also { it.mkdirs() }
        val fileName = extractFileName(task.url)
        val file = File(dir, "${System.currentTimeMillis()}_$fileName")

        Log.d(TAG, "Downloading ${task.url} -> ${file.name}")

        val request = Request.Builder()
            .url(task.url)
            .build()

        val response = httpClient.newCall(request).execute()
        if (!response.isSuccessful) {
            Log.e(TAG, "HTTP ${response.code} when downloading ${task.url}")
            return null
        }

        // 下载文件
        response.body?.byteStream()?.use { input ->
            file.outputStream().use { output ->
                input.copyTo(output, BUFFER_SIZE)
            }
        }

        // 验证下载的文件
        if (file.length() == 0L) {
            file.delete()
            Log.e(TAG, "Downloaded file is empty: ${task.url}")
            return null
        }

        Log.d(TAG, "Downloaded ${file.length()} bytes from ${task.url}")

        // 保存到数据库
        val docId = db.documentDao().insert(
            DocumentRecord(
                smsId = task.smsId,
                fileName = fileName,
                filePath = file.absolutePath,
                fileSize = file.length(),
                sourceUrl = task.url,
                downloadTime = System.currentTimeMillis(),
                displayName = fileName
            )
        )

        // 解析PDF并同步到数据库
        com.shanfuchun.courtassistant.service.parser.PdfParser.parseAndSync(context, db, docId)

        return docId
    }

    /**
     * 从URL提取文件名
     */
    private fun extractFileName(url: String): String {
        return try {
            val path = URI(url).path
            val name = path.substringAfterLast("/")
            if (name.isNotBlank() && name.length < 100) name else "document.pdf"
        } catch (e: Exception) {
            "document.pdf"
        }
    }

    /**
     * 检查文件是否有效
     */
    fun isValidPdfFile(file: File): Boolean {
        return file.exists() && file.length() > 0 && file.length() < 100 * 1024 * 1024 // 100MB限制
    }

    /**
     * 清理无效的PDF文件
     */
    fun cleanupInvalidFiles(context: Context): Int {
        val dir = File(context.filesDir, "pdfs")
        if (!dir.exists()) return 0

        var cleaned = 0
        dir.listFiles { file ->
            file.extension.equals("pdf", ignoreCase = true)
        }?.forEach { file ->
            if (!isValidPdfFile(file)) {
                file.delete()
                cleaned++
                Log.d(TAG, "Cleaned invalid PDF file: ${file.name}")
            }
        }

        return cleaned
    }
}

