import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import java.io.File

/**
 * PDF 下载处理器接口
 *
 * 定义处理 PDF 下载的通用接口
 */
interface PdfDownloadHandler {
    suspend fun handleDownload(
        context: Context,
        db: AppDatabase,
        smsId: Long,
        url: String,
        displayName: String
    ): Boolean
}

/**
 * 基于文件的 PDF 下载处理器
 *
 * 直接下载 PDF 文件并保存到本地
 */
class FileDownloadHandler : PdfDownloadHandler {

    companion object {
        private const val TAG = "FileDownloadHandler"
        private const val MAX_RETRIES = 3
        private const val RETRY_DELAY_MS = 2000L
    }

    override suspend fun handleDownload(
        context: Context,
        db: AppDatabase,
        smsId: Long,
        url: String,
        displayName: String
    ): Boolean = withContext(Dispatchers.IO) {
        var lastError: Exception? = null

        repeat(MAX_RETRIES) { attempt ->
            try {
                Log.d(TAG, "Download attempt $attempt: $url")

                val client = NetworkHelper.createClient(
                    timeout = 30L,
                    readTimeout = 60L
                )

                val request = okhttp3.Request.Builder()
                    .url(url)
                    .addHeader("User-Agent", "Mozilla/5.0")
                    .build()

                val response = client.newCall(request).execute()

                if (!response.isSuccessful) {
                    throw Exception("HTTP ${response.code}")
                }

                val contentType = response.header("Content-Type", "")
                if (!contentType.contains("pdf", ignoreCase = true) &&
                    !url.lowercase().endsWith(".pdf")) {
                    Log.w(TAG, "Not a PDF: $contentType")
                    return@repeat false
                }

                val file = FileUtils.createPdfFile(context, displayName)
                response.body?.byteStream()?.use { input ->
                    file.outputStream().use { output -> input.copyTo(output) }
                }

                if (file.length() == 0L) {
                    file.delete()
                    throw Exception("Empty file")
                }

                // 保存到数据库
                val docRecord = DocumentRecord(
                    smsId = smsId,
                    fileName = file.name,
                    filePath = file.absolutePath,
                    fileSize = file.length(),
                    sourceUrl = url,
                    downloadTime = System.currentTimeMillis(),
                    parseStatus = 0, // 待识别
                    displayName = displayName
                )

                db.documentDao().insert(docRecord)

                Log.d(TAG, "Download successful: ${file.name}")
                return@repeat true

            } catch (e: Exception) {
                Log.e(TAG, "Download attempt $attempt failed", e)
                lastError = e

                // 最后一次尝试不再重试
                if (attempt == MAX_RETRIES) {
                    return@repeat false
                }

                // 等待后重试
                kotlinx.coroutines.delay(RETRY_DELAY_MS)
            }
        }

        // 返回最终结果
        return lastError == null
    }
}

